"""Tools management commands for ctxcli."""

import asyncio
import json
from datetime import datetime
from pathlib import Path
from typing import Annotated

import typer
from rich.console import Console

from context_surfaces.cli.ctxcli.config import (
    ConfigManager,
    ToolsCache,
    ToolSchema,
)

console = Console()

# Create tools subcommand group
tools_app = typer.Typer(
    name="tools",
    help="Manage tools cache",
    no_args_is_help=True,
)


def _get_config_and_profile(ctx: typer.Context) -> tuple[ConfigManager, str]:
    """Get config manager and profile from context."""
    config_manager = ctx.obj.get("config_manager") if ctx.obj else None
    if config_manager is None:
        config_manager = ConfigManager()

    profile_name = ctx.obj.get("profile") if ctx.obj else "default"
    return config_manager, profile_name


def _ensure_initialized(config_manager: ConfigManager, profile_name: str) -> None:
    """Ensure profile is initialized, exit if not."""
    if not config_manager.is_initialized(profile_name):
        console.print(
            f"[bold red]Error:[/bold red] Profile '{profile_name}' is not initialized.\n"
            "Run [cyan]ctxcli init[/cyan] first."
        )
        raise typer.Exit(code=1)


@tools_app.command("refresh")
def tools_refresh(ctx: typer.Context) -> None:
    """Force refresh the tools cache.

    Fetches the latest tools list from the MCP server regardless of TTL.

    [bold]Example:[/bold]
        ctxcli tools refresh
    """
    config_manager, profile_name = _get_config_and_profile(ctx)
    _ensure_initialized(config_manager, profile_name)

    profile = config_manager.get_profile(profile_name)

    console.print(f"Refreshing tools from [cyan]{profile.mcp_url}[/cyan]...")

    try:
        tools = asyncio.run(_fetch_tools(profile.mcp_url, profile.agent_key))
    except Exception as e:
        console.print(f"[bold red]Error:[/bold red] Failed to refresh: {e}")
        raise typer.Exit(code=1) from e

    # Update cache
    profile.tools_cache = ToolsCache(
        fetched_at=datetime.now(),
        tools=[
            ToolSchema(
                name=tool.get("name", ""),
                description=tool.get("description", ""),
                input_schema=tool.get("inputSchema", {}),
            )
            for tool in tools
        ],
    )
    config_manager.set_profile(profile_name, profile)

    console.print(f"[green]✓[/green] Refreshed {len(tools)} tools")


@tools_app.command("raw")
def tools_raw(
    ctx: typer.Context,
    tool_name: Annotated[str, typer.Argument(help="Original MCP tool name")],
    args: Annotated[
        str | None,
        typer.Option("--args", help="Tool arguments as JSON string"),
    ] = None,
    args_file: Annotated[
        Path | None,
        typer.Option("--args-file", help="Path to JSON file with arguments"),
    ] = None,
    output: Annotated[
        str,
        typer.Option("--output", "-o", help="Output format: table, json, yaml"),
    ] = "table",
) -> None:
    """Call a tool by its original MCP name.

    Escape hatch for calling tools that don't transform well.

    [bold]Examples:[/bold]
        ctxcli tools raw filter_user_by_email --args '{"value": "test@example.com"}'
        ctxcli tools raw get_order_by_id --args-file ./args.json
    """
    config_manager, profile_name = _get_config_and_profile(ctx)
    _ensure_initialized(config_manager, profile_name)

    profile = config_manager.get_profile(profile_name)

    # Parse arguments
    arguments = _parse_arguments(args, args_file)

    # Call the tool
    try:
        result = asyncio.run(_call_tool(profile.mcp_url, profile.agent_key, tool_name, arguments))
    except Exception as e:
        console.print(f"[bold red]Error:[/bold red] {e}")
        raise typer.Exit(code=1) from e

    # Format output
    _render_output(result, output)


def _parse_arguments(args: str | None, args_file: Path | None) -> dict:
    """Parse tool arguments from JSON string or file."""
    if args is not None:
        try:
            return json.loads(args)
        except json.JSONDecodeError as e:
            console.print(f"[bold red]Error:[/bold red] Invalid JSON: {e}")
            raise typer.Exit(code=1) from e

    if args_file is not None:
        if not args_file.exists():
            console.print(f"[bold red]Error:[/bold red] File not found: {args_file}")
            raise typer.Exit(code=1)
        try:
            return json.loads(args_file.read_text())
        except json.JSONDecodeError as e:
            console.print(f"[bold red]Error:[/bold red] Invalid JSON in file: {e}")
            raise typer.Exit(code=1) from e

    return {}


def _render_output(result: dict, output_format: str) -> None:
    """Render the result in the specified format."""
    if output_format == "json":
        print(json.dumps(result, indent=2))
    elif output_format == "yaml":
        import yaml
        print(yaml.safe_dump(result, default_flow_style=False))
    else:  # table
        from context_surfaces.cli.models.output import TableOutput
        from context_surfaces.cli.services.output_formatter import OutputFormatter

        formatter = OutputFormatter()
        table = TableOutput.from_dict(result, title="Result")
        formatter.render(table)


async def _fetch_tools(mcp_url: str, agent_key: str) -> list[dict]:
    """Fetch tools from MCP server."""
    from context_surfaces.mcp_client import MCPClient

    async with MCPClient(mcp_url=mcp_url, agent_key=agent_key) as mcp:
        return await mcp.list_tools()


async def _call_tool(mcp_url: str, agent_key: str, tool_name: str, arguments: dict) -> dict:
    """Call a tool on the MCP server."""
    from context_surfaces.mcp_client import MCPClient

    async with MCPClient(mcp_url=mcp_url, agent_key=agent_key) as mcp:
        return await mcp.call_tool(tool_name, arguments)

